// // This module decodes a 2-bit input to a 1-bit output. Output is the least significant bit of the input, except when input is '10', then output is '1'.
module two_bit_encoder
    ( 
    input   [1:0]  data,
    output  reg    q
    );

    always @(*)
    begin
        if (data == 2'b10)
            q = 1'b0;
        else
            q = data[1];
    end

endmodule
